package output

import (
	"fmt"
	"strings"
	"time"

	"github.com/jasonmassey/devdash-cli-go/internal/api"
)

// Status icons matching the Bash version exactly.
const (
	IconPending    = "○"
	IconInProgress = "●"
	IconCompleted  = "✓"
	IconFailed     = "✗"
	IconStale      = "⚠"
	IconSkipped    = "⊘"
)

// StatusIcon returns the icon for a bead status.
func StatusIcon(status string) string {
	switch status {
	case "pending":
		return IconPending
	case "in_progress":
		return IconInProgress
	case "completed":
		return IconCompleted
	case "failed":
		return IconFailed
	default:
		return IconPending
	}
}

// JobStatusIcon returns the icon for a job status.
func JobStatusIcon(status string) string {
	switch status {
	case "queued":
		return IconPending
	case "running":
		return IconInProgress
	case "completed":
		return IconCompleted
	case "failed":
		return IconFailed
	case "skipped":
		return IconSkipped
	default:
		return IconPending
	}
}

// FormatReadyLine formats a bead for the `ready` command output.
func FormatReadyLine(b api.Bead) string {
	parts := []string{
		fmt.Sprintf("%s %s", IconPending, beadID(b)),
		fmt.Sprintf("[P%d]", b.Priority),
	}
	if b.BurnIntelligence != nil && b.BurnIntelligence.AutomabilityGrade != "" {
		parts = append(parts, fmt.Sprintf("[%s]", b.BurnIntelligence.AutomabilityGrade))
	}
	parts = append(parts, fmt.Sprintf("[%s]", b.BeadType))
	parts = append(parts, fmt.Sprintf("- %s", b.Subject))
	return strings.Join(parts, " ")
}

// FormatListLine formats a bead for the `list` command output.
func FormatListLine(b api.Bead) string {
	icon := StatusIcon(b.Status)
	suffix := ""
	if b.Status == "pending" && len(b.BlockedBy) > 0 {
		suffix = "(blocked)"
	}
	return fmt.Sprintf("%s %s [P%d] [%s] - %s%s",
		icon, beadID(b), b.Priority, b.BeadType, b.Subject, suffix)
}

// FormatBlockedLine formats a bead for the `blocked` command output.
func FormatBlockedLine(b api.Bead) string {
	blockers := strings.Join(shortIDs(b.BlockedBy), ", ")
	return fmt.Sprintf("%s %s [P%d] - %s  blocked by: %s",
		IconPending, beadID(b), b.Priority, b.Subject, blockers)
}

// FormatStaleLine formats a bead for the `stale` command output.
func FormatStaleLine(b api.Bead) string {
	return fmt.Sprintf("  %s %s — %s\n    Stale for %dm (since %s)",
		IconStale, beadID(b), b.Subject, b.StaleMinutes, b.StaleSince)
}

// FormatStats formats project statistics.
func FormatStats(total, pending, inProgress, completed, blocked, ready int) string {
	return fmt.Sprintf("Total:       %d\nPending:     %d\nIn Progress: %d\nCompleted:   %d\nBlocked:     %d\nReady:       %d",
		total, pending, inProgress, completed, blocked, ready)
}

// FormatJobLine formats a job for listing.
func FormatJobLine(j api.Job) string {
	icon := JobStatusIcon(j.Status)
	prompt := j.Prompt
	if len(prompt) > 70 {
		prompt = prompt[:70] + "..."
	}
	return fmt.Sprintf("%s %s [%s] %s  %s",
		icon, shortID(j.ID), j.Status, prompt, j.CreatedAt)
}

// FormatJobFailureLine formats a failed job for listing.
func FormatJobFailureLine(j api.Job) string {
	errMsg := j.Error
	if len(errMsg) > 80 {
		errMsg = errMsg[:80]
	}
	return fmt.Sprintf("%s %s %s  %s", IconFailed, shortID(j.ID), errMsg, j.CreatedAt)
}

// ParseSince converts a --since value to a time.Time.
// Supports: Nh (hours), Nd (days), Nw (weeks), YYYY-MM-DD.
func ParseSince(since string) (time.Time, error) {
	if since == "" {
		return time.Time{}, fmt.Errorf("empty --since value")
	}

	now := time.Now().UTC()

	// Try date format first
	if t, err := time.Parse("2006-01-02", since); err == nil {
		return t, nil
	}

	if len(since) < 2 {
		return time.Time{}, fmt.Errorf("invalid --since format: %q", since)
	}

	unit := since[len(since)-1]
	numStr := since[:len(since)-1]
	var n int
	if _, err := fmt.Sscanf(numStr, "%d", &n); err != nil {
		return time.Time{}, fmt.Errorf("invalid --since format: %q", since)
	}

	switch unit {
	case 'h':
		return now.Add(-time.Duration(n) * time.Hour), nil
	case 'd':
		return now.AddDate(0, 0, -n), nil
	case 'w':
		return now.AddDate(0, 0, -n*7), nil
	default:
		return time.Time{}, fmt.Errorf("invalid --since unit %q (use h, d, or w)", string(unit))
	}
}

// FormatSinceISO converts a --since value to an ISO 8601 string for API queries.
func FormatSinceISO(since string) (string, error) {
	t, err := ParseSince(since)
	if err != nil {
		return "", err
	}
	return t.Format("2006-01-02T15:04:05.000Z"), nil
}

func beadID(b api.Bead) string {
	if b.LocalBeadID != "" {
		return b.LocalBeadID
	}
	return shortID(b.ID)
}

func shortID(id string) string {
	if len(id) >= 8 {
		return id[:8]
	}
	return id
}

func shortIDs(ids []string) []string {
	out := make([]string, len(ids))
	for i, id := range ids {
		out[i] = shortID(id)
	}
	return out
}

package api

import (
	"strings"
	"time"
)

// FlexTime handles multiple date formats from the API.
type FlexTime struct {
	time.Time
}

func (ft *FlexTime) UnmarshalJSON(b []byte) error {
	s := strings.Trim(string(b), `"`)
	if s == "" || s == "null" {
		return nil
	}

	// Try RFC3339 first, then space-separated format
	for _, layout := range []string{
		time.RFC3339,
		"2006-01-02T15:04:05.000Z",
		"2006-01-02T15:04:05Z",
		"2006-01-02 15:04:05Z",
		"2006-01-02 15:04:05.000Z",
	} {
		if t, err := time.Parse(layout, s); err == nil {
			ft.Time = t
			return nil
		}
	}

	// Last resort: replace space with T and try again
	normalized := strings.Replace(s, " ", "T", 1)
	t, err := time.Parse(time.RFC3339, normalized)
	if err != nil {
		return err
	}
	ft.Time = t
	return nil
}

// Bead represents a devdash issue/task.
type Bead struct {
	ID           string `json:"id"`
	LocalBeadID  string `json:"localBeadId,omitempty"`
	ProjectID    string `json:"projectId,omitempty"`
	ProjectName  string `json:"projectName,omitempty"`
	Subject      string `json:"subject"`
	Description  string `json:"description,omitempty"`
	Status       string `json:"status"`
	Priority     int    `json:"priority"`
	BeadType     string `json:"beadType"`
	AssignedTo   string `json:"assignedTo,omitempty"`
	ParentBeadID string `json:"parentBeadId,omitempty"`

	BlockedBy []string `json:"blockedBy,omitempty"`
	Blocks    []string `json:"blocks,omitempty"`

	PreInstructions  string            `json:"preInstructions,omitempty"`
	CompletionResult *CompletionResult `json:"completionResult,omitempty"`
	BurnIntelligence *BurnIntelligence `json:"burnIntelligence,omitempty"`

	DueDate          string `json:"dueDate,omitempty"`
	EstimatedMinutes int    `json:"estimatedMinutes,omitempty"`
	StaleSince       string `json:"staleSince,omitempty"`
	StaleMinutes     int    `json:"staleMinutes,omitempty"`

	CreatedAt FlexTime `json:"createdAt"`
	UpdatedAt FlexTime `json:"updatedAt"`
}

// CompletionResult holds metadata from closing an issue.
type CompletionResult struct {
	Summary string `json:"summary,omitempty"`
	PR      string `json:"pr,omitempty"`
	Commit  string `json:"commit,omitempty"`
}

// BurnIntelligence holds scoring data.
type BurnIntelligence struct {
	ComplexityScore   int      `json:"complexityScore"`
	AutomabilityScore int      `json:"automabilityScore"`
	AutomabilityGrade string   `json:"automabilityGrade"`
	Factors           []string `json:"factors,omitempty"`
	ScoredAt          string   `json:"scoredAt,omitempty"`
}

// Project represents a devdash project.
type Project struct {
	ID          string `json:"id"`
	Name        string `json:"name"`
	Description string `json:"description,omitempty"`
	GithubRepo  string `json:"githubRepo,omitempty"`
	CreatedAt   string `json:"createdAt,omitempty"`
	UpdatedAt   string `json:"updatedAt,omitempty"`
}

// Job represents an async job.
type Job struct {
	ID              string           `json:"id"`
	BeadID          string           `json:"beadId,omitempty"`
	ProjectID       string           `json:"projectId,omitempty"`
	Status          string           `json:"status"`
	WorkerType      string           `json:"workerType,omitempty"`
	Prompt          string           `json:"prompt,omitempty"`
	OutputLog       string           `json:"output_log,omitempty"`
	Error           string           `json:"error,omitempty"`
	FailureAnalysis *FailureAnalysis `json:"failureAnalysis,omitempty"`
	Result          interface{}      `json:"result,omitempty"`
	CreatedAt       string           `json:"createdAt,omitempty"`
	StartedAt       string           `json:"startedAt,omitempty"`
	CompletedAt     string           `json:"completedAt,omitempty"`
}

// FailureAnalysis holds diagnostic info for failed jobs.
type FailureAnalysis struct {
	Summary    string `json:"summary,omitempty"`
	RootCause  string `json:"rootCause,omitempty"`
	Suggestion string `json:"suggestion,omitempty"`
}

// TeamMember represents a project member.
type TeamMember struct {
	Name     string `json:"name,omitempty"`
	Username string `json:"username,omitempty"`
	Email    string `json:"email"`
	Role     string `json:"role"`
	Status   string `json:"status,omitempty"`
}

// CreateBeadRequest is the body for POST /beads.
type CreateBeadRequest struct {
	ProjectID        string `json:"projectId"`
	Subject          string `json:"subject"`
	Description      string `json:"description,omitempty"`
	BeadType         string `json:"beadType,omitempty"`
	Priority         *int   `json:"priority,omitempty"`
	ParentBeadID     string `json:"parentBeadId,omitempty"`
	DueDate          string `json:"dueDate,omitempty"`
	EstimatedMinutes *int   `json:"estimatedMinutes,omitempty"`
}

// UpdateBeadRequest is the body for PATCH /beads/{id}.
type UpdateBeadRequest struct {
	ProjectID        string  `json:"projectId"`
	Subject          *string `json:"subject,omitempty"`
	Description      *string `json:"description,omitempty"`
	Status           *string `json:"status,omitempty"`
	Priority         *int    `json:"priority,omitempty"`
	AssignedTo       *string `json:"assignedTo,omitempty"`
	ParentBeadID     *string `json:"parentBeadId,omitempty"`
	PreInstructions  *string `json:"preInstructions,omitempty"`
	DueDate          *string `json:"dueDate,omitempty"`
	EstimatedMinutes *int    `json:"estimatedMinutes,omitempty"`
}

// CloseBeadRequest is the body for closing a single bead.
type CloseBeadRequest struct {
	ProjectID        string            `json:"projectId"`
	Status           string            `json:"status"`
	CompletionResult *CompletionResult `json:"completionResult,omitempty"`
}

// BulkCloseRequest is the body for POST /beads/bulk/close.
type BulkCloseRequest struct {
	ProjectID string          `json:"projectId"`
	Beads     []BulkCloseItem `json:"beads"`
}

// BulkCloseItem is a single bead in a bulk close.
type BulkCloseItem struct {
	ID               string            `json:"id"`
	CompletionResult *CompletionResult `json:"completionResult,omitempty"`
}

// ReportRequest is the body for POST /beads/{id}/report.
type ReportRequest struct {
	ProjectID    string `json:"projectId"`
	Status       string `json:"status"`
	Summary      string `json:"summary,omitempty"`
	FilesChanged *int   `json:"filesChanged,omitempty"`
	Branch       string `json:"branch,omitempty"`
	CommitSha    string `json:"commitSha,omitempty"`
	Error        string `json:"error,omitempty"`
}

// AddDependencyRequest is the body for POST /beads/{id}/dependencies.
type AddDependencyRequest struct {
	ProjectID string `json:"projectId"`
	BlockedBy string `json:"blockedBy"`
}

